import boto3
import re
from urllib.parse import urlparse

# Allowlist of permitted domains for SNS subscription endpoints
ALLOWED_DOMAINS = [
    "api.example.com",
    "webhooks.example.com",
    "notifications.example.com",
]

ALLOWED_PROTOCOLS = ["https"]

# Allowed topic ARN pattern
ALLOWED_TOPIC_ARN_PATTERN = re.compile(
    r"^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$"
)


def validate_endpoint_url(url):
    """Validate that the endpoint URL is an allowed HTTPS endpoint."""
    try:
        parsed = urlparse(url)
    except Exception:
        raise ValueError(f"Invalid URL format: {url}")

    if parsed.scheme != "https":
        raise ValueError("Only HTTPS endpoints are allowed.")

    if not parsed.hostname:
        raise ValueError("URL must contain a valid hostname.")

    # Prevent SSRF: block internal/private IP ranges and localhost
    hostname = parsed.hostname.lower()

    blocked_hostnames = ["localhost", "127.0.0.1", "0.0.0.0", "::1", "metadata.google.internal"]
    for blocked in blocked_hostnames:
        if hostname == blocked:
            raise ValueError(f"Endpoint hostname '{hostname}' is not allowed.")

    # Check against allowlist of domains
    domain_allowed = False
    for allowed_domain in ALLOWED_DOMAINS:
        if hostname == allowed_domain or hostname.endswith("." + allowed_domain):
            domain_allowed = True
            break

    if not domain_allowed:
        raise ValueError(
            f"Domain '{hostname}' is not in the allowed domains list. "
            f"Allowed domains: {ALLOWED_DOMAINS}"
        )

    # Block URLs with credentials embedded
    if parsed.username or parsed.password:
        raise ValueError("URLs with embedded credentials are not allowed.")

    # Block non-standard ports
    if parsed.port and parsed.port != 443:
        raise ValueError("Only standard HTTPS port (443) is allowed.")

    return url


def validate_topic_arn(topic_arn):
    """Validate that the topic ARN matches expected format."""
    if not ALLOWED_TOPIC_ARN_PATTERN.match(topic_arn):
        raise ValueError(f"Invalid SNS Topic ARN format: {topic_arn}")
    return topic_arn


def validate_protocol(protocol):
    """Validate that the protocol is in the allowed list."""
    if protocol not in ALLOWED_PROTOCOLS:
        raise ValueError(
            f"Protocol '{protocol}' is not allowed. Allowed protocols: {ALLOWED_PROTOCOLS}"
        )
    return protocol


def create_sns_subscription(topic_arn, protocol, endpoint):
    """Create an SNS subscription with validated inputs."""
    # Validate all inputs before making the API call
    validated_topic = validate_topic_arn(topic_arn)
    validated_protocol = validate_protocol(protocol)
    validated_endpoint = validate_endpoint_url(endpoint)

    sns_client = boto3.client("sns")

    try:
        response = sns_client.subscribe(
            TopicArn=validated_topic,
            Protocol=validated_protocol,
            Endpoint=validated_endpoint,
            ReturnSubscriptionArn=True,
        )
        subscription_arn = response.get("SubscriptionArn", "PendingConfirmation")
        print(f"Subscription created successfully. ARN: {subscription_arn}")
        return response
    except sns_client.exceptions.NotFoundException:
        print(f"Error: Topic '{validated_topic}' not found.")
        raise
    except sns_client.exceptions.AuthorizationErrorException:
        print("Error: Not authorized to subscribe to this topic.")
        raise
    except Exception as e:
        print(f"Error creating subscription: {e}")
        raise


def list_subscriptions(topic_arn):
    """List existing subscriptions for a topic."""
    validated_topic = validate_topic_arn(topic_arn)
    sns_client = boto3.client("sns")

    try:
        response = sns_client.list_subscriptions_by_topic(TopicArn=validated_topic)
        subscriptions = response.get("Subscriptions", [])
        print(f"\nSubscriptions for topic: {validated_topic}")
        for sub in subscriptions:
            print(f"  - Endpoint: {sub['Endpoint']}, Protocol: {sub['Protocol']}, "
                  f"ARN: {sub['SubscriptionArn']}")
        return subscriptions
    except Exception as e:
        print(f"Error listing subscriptions: {e}")
        raise


def main():
    print("SNS Subscription Manager")
    print(f"Allowed endpoint domains: {ALLOWED_DOMAINS}")
    print("-" * 50)

    topic_arn = input("Enter SNS Topic ARN: ").strip()
    endpoint_url = input("Enter webhook endpoint URL (HTTPS only): ").strip()

    try:
        create_sns_subscription(
            topic_arn=topic_arn,
            protocol="https",
            endpoint=endpoint_url,
        )
    except ValueError as e:
        print(f"Validation error: {e}")
    except Exception as e:
        print(f"Failed to create subscription: {e}")


if __name__ == "__main__":
    main()